/* Basic CSS Reset */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background-color: #f4f7f6; /* Light grey background */
    display: flex;
    justify-content: center; /* Center horizontally */
    align-items: center; /* Center vertically */
    min-height: 100vh; /* Full viewport height */
    margin: 20px; /* Some margin around the app */
}

#app {
    background-color: #ffffff;
    padding: 30px;
    border-radius: 10px;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
    width: 100%;
    max-width: 500px;
}

h1 {
    text-align: center;
    color: #333;
    margin-bottom: 25px;
    font-size: 2.2em;
}

.input-area {
    display: flex;
    margin-bottom: 25px;
}

#task-input {
    flex-grow: 1; /* Allows input to take up available space */
    padding: 12px 15px;
    border: 1px solid #ddd;
    border-radius: 5px;
    font-size: 1em;
    outline: none; /* Remove blue outline on focus */
}

#task-input:focus {
    border-color: #5cb85c; /* Highlight border on focus */
}

#add-task-btn {
    padding: 12px 20px;
    background-color: #5cb85c; /* Green button */
    color: white;
    border: none;
    border-radius: 5px;
    cursor: pointer;
    margin-left: 10px;
    font-size: 1em;
    transition: background-color 0.2s ease; /* Smooth hover effect */
}

#add-task-btn:hover {
    background-color: #4cae4c; /* Darker green on hover */
}

#task-list {
    list-style: none; /* Remove bullet points */
    padding: 0;
}

#task-list li {
    background-color: #f9f9f9;
    padding: 15px;
    margin-bottom: 10px;
    border-radius: 5px;
    display: flex;
    justify-content: space-between; /* Space out task text and buttons */
    align-items: center;
    box-shadow: 0 2px 5px rgba(0, 0, 0, 0.05);
    transition: background-color 0.2s ease;
}

#task-list li span {
    flex-grow: 1; /* Allow task text to fill space */
    font-size: 1.1em;
    color: #333;
    word-break: break-word; /* Prevent long words from overflowing */
}

/* Style for completed tasks */
#task-list li.completed {
    text-decoration: line-through;
    color: #888;
    background-color: #e9e9e9;
}

.complete-btn,
.delete-btn {
    padding: 8px 12px;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9em;
    margin-left: 8px;
    transition: background-color 0.2s ease, transform 0.1s ease;
}

.complete-btn {
    background-color: #0275d8; /* Blue for complete */
    color: white;
}

.complete-btn:hover {
    background-color: #025aa5;
    transform: translateY(-1px);
}

.delete-btn {
    background-color: #d9534f; /* Red for delete */
    color: white;
}

.delete-btn:hover {
    background-color: #c9302c;
    transform: translateY(-1px);
}

// 1. Get DOM Elements
const taskInput = document.getElementById('task-input');
const addTaskBtn = document.getElementById('add-task-btn');
const taskList = document.getElementById('task-list');

// 2. addTask Function
function addTask() {
    const taskText = taskInput.value.trim(); // Get value and remove leading/trailing whitespace

    if (taskText === '') {
        alert('Please enter a task!');
        return; // Stop the function if input is empty
    }

    // Create the main list item (<li>)
    const listItem = document.createElement('li');

    // Create a span for the task text
    const taskSpan = document.createElement('span');
    taskSpan.textContent = taskText;

    // Create the 'Complete' button
    const completeBtn = document.createElement('button');
    completeBtn.textContent = 'Complete';
    completeBtn.classList.add('complete-btn'); // Add a class for styling and event delegation

    // Create the 'Delete' button
    const deleteBtn = document.createElement('button');
    deleteBtn.textContent = 'Delete';
    deleteBtn.classList.add('delete-btn'); // Add a class for styling and event delegation

    // Append the span and buttons to the list item
    listItem.appendChild(taskSpan);
    listItem.appendChild(completeBtn);
    listItem.appendChild(deleteBtn);

    // Append the complete list item to the task list (<ul>)
    taskList.appendChild(listItem);

    // Clear the input field
    taskInput.value = '';
    taskInput.focus(); // Keep focus on the input for quick adding
}

// 3. Event Listeners for Adding Tasks
addTaskBtn.addEventListener('click', addTask);

taskInput.addEventListener('keydown', function(event) {
    if (event.key === 'Enter') {
        addTask();
    }
});

// 4. Event Delegation for Task Actions (Complete/Delete)
taskList.addEventListener('click', function(event) {
    const target = event.target; // The element that was clicked

    // Check if the clicked element has the 'complete-btn' class
    if (target.classList.contains('complete-btn')) {
        // Toggle the 'completed' class on the parent <li> element
        // The parentNode of the button is the <li>
        target.parentNode.classList.toggle('completed');
    }

    // Check if the clicked element has the 'delete-btn' class
    if (target.classList.contains('delete-btn')) {
        // Remove the parent <li> element from the DOM
        target.parentNode.remove();
    }
});

